import React, { useState, useEffect, useCallback } from 'react';
import { courtierAPI } from '../../services/courtierAPI';

const STATUS_LABELS = {
  draft: 'Brouillon', soumis: 'Soumis', en_analyse: 'En analyse',
  devis_genere: 'Devis généré', valide: 'Validé', rejete: 'Rejeté',
};

function CreateDossierModal({ onClose, onCreated }) {
  const [form, setForm] = useState({ nom: '', secteur: '', taille: 'PME', client_email: '' });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const set = (k, v) => setForm((f) => ({ ...f, [k]: v }));

  const handleSubmit = async () => {
    if (!form.nom.trim()) { setError('Nom de l\'entreprise requis'); return; }
    setLoading(true);
    setError('');
    try {
      const body = {
        entreprise: { nom: form.nom, secteur: form.secteur || null, taille: form.taille || null },
        client_email: form.client_email || null,
      };
      const res = await courtierAPI.createDossier(body);
      onCreated(res.data);
    } catch (e) {
      setError(e.response?.data?.detail || 'Erreur lors de la création');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="crt-modal-overlay" onClick={onClose}>
      <div className="crt-modal" onClick={(e) => e.stopPropagation()}>
        <h3>Nouveau dossier</h3>
        {error && <div style={{ color: '#ff4466', fontSize: 13, marginBottom: 12 }}>{error}</div>}
        <div className="crt-form-group">
          <label>Nom de l'entreprise *</label>
          <input className="crt-input" value={form.nom} onChange={(e) => set('nom', e.target.value)} placeholder="Ex: Acme SAS" />
        </div>
        <div className="crt-form-group">
          <label>Secteur</label>
          <input className="crt-input" value={form.secteur} onChange={(e) => set('secteur', e.target.value)} placeholder="Ex: Finance, Santé..." />
        </div>
        <div className="crt-form-group">
          <label>Taille</label>
          <select className="crt-input crt-select" value={form.taille} onChange={(e) => set('taille', e.target.value)}>
            <option value="Startup">Startup</option>
            <option value="PME">PME</option>
            <option value="ETI">ETI</option>
            <option value="GE">Grande Entreprise</option>
          </select>
        </div>
        <div className="crt-form-group">
          <label>Email client (optionnel)</label>
          <input className="crt-input" value={form.client_email} onChange={(e) => set('client_email', e.target.value)} placeholder="client@example.com" />
        </div>
        <div className="crt-modal-actions">
          <button className="crt-btn crt-btn-ghost" onClick={onClose}>Annuler</button>
          <button className="crt-btn crt-btn-primary" onClick={handleSubmit} disabled={loading}>
            {loading ? 'Création...' : 'Créer le dossier'}
          </button>
        </div>
      </div>
    </div>
  );
}

export default function CourtierDossiers() {
  const [dossiers, setDossiers] = useState([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [showCreate, setShowCreate] = useState(false);
  const [actionLoading, setActionLoading] = useState(null);

  const load = useCallback(async () => {
    setLoading(true);
    setError('');
    try {
      const params = {};
      if (search) params.search = search;
      if (statusFilter) params.status = statusFilter;
      const res = await courtierAPI.getDossiers(params);
      setDossiers(res.data.dossiers);
      setTotal(res.data.total);
    } catch {
      setError('Impossible de charger les dossiers');
    } finally {
      setLoading(false);
    }
  }, [search, statusFilter]);

  useEffect(() => { load(); }, [load]);

  const handleSoumettre = async (id) => {
    setActionLoading(id + '-soumettre');
    try {
      await courtierAPI.soumettreDossier(id);
      load();
    } catch (e) {
      alert(e.response?.data?.detail || 'Erreur');
    } finally {
      setActionLoading(null);
    }
  };

  const handleDemanderDevis = async (id) => {
    setActionLoading(id + '-devis');
    try {
      await courtierAPI.demanderDevis(id);
      load();
    } catch (e) {
      alert(e.response?.data?.detail || 'Erreur');
    } finally {
      setActionLoading(null);
    }
  };

  return (
    <div>
      <div className="crt-search-row">
        <input
          className="crt-search"
          placeholder="Rechercher une entreprise..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
        <select className="crt-select" value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)}>
          <option value="">Tous les statuts</option>
          {Object.entries(STATUS_LABELS).map(([k, v]) => (
            <option key={k} value={k}>{v}</option>
          ))}
        </select>
        <button className="crt-btn crt-btn-primary" onClick={() => setShowCreate(true)}>
          <i className="ti ti-plus" /> Nouveau dossier
        </button>
      </div>

      <div className="crt-table-wrap">
        <div className="crt-table-header">
          <h2>Dossiers ({total})</h2>
        </div>

        {loading && <div className="crt-loading"><i className="ti ti-loader" /> Chargement...</div>}
        {error && <div className="crt-error"><i className="ti ti-alert-circle" /> {error}</div>}

        {!loading && !error && (
          <table className="crt-table">
            <thead>
              <tr>
                <th>Entreprise</th>
                <th>Secteur</th>
                <th>Taille</th>
                <th>Client</th>
                <th>Statut</th>
                <th>Score</th>
                <th>Date</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {dossiers.map((d) => (
                <tr key={d.id}>
                  <td style={{ fontWeight: 500 }}>{d.company}</td>
                  <td style={{ color: 'var(--crt-muted)', fontSize: 13 }}>{d.secteur || '—'}</td>
                  <td style={{ fontSize: 13 }}>{d.taille || '—'}</td>
                  <td style={{ fontSize: 13, color: 'var(--crt-muted)' }}>
                    {d.client_email ? (
                      <span style={{ color: 'var(--crt-accent)' }}>{d.client_email}</span>
                    ) : '—'}
                  </td>
                  <td>
                    <span className={`crt-badge badge-${d.status}`}>
                      {STATUS_LABELS[d.status] || d.status}
                    </span>
                  </td>
                  <td>
                    {d.score != null ? (
                      <div className="crt-score-bar">
                        <div className="score-bar-track" style={{ width: 60 }}>
                          <div className="score-bar-fill" style={{ width: `${d.score}%` }} />
                        </div>
                        <span style={{ fontSize: 12, color: 'var(--crt-muted)' }}>{d.score}</span>
                      </div>
                    ) : '—'}
                  </td>
                  <td style={{ color: 'var(--crt-muted)', fontSize: 13 }}>{d.date_creation}</td>
                  <td>
                    <div style={{ display: 'flex', gap: 6 }}>
                      {d.status === 'draft' && (
                        <button
                          className="crt-btn crt-btn-ghost"
                          style={{ padding: '5px 10px', fontSize: 12 }}
                          disabled={actionLoading === d.id + '-soumettre'}
                          onClick={() => handleSoumettre(d.id)}
                        >
                          <i className="ti ti-send" /> Soumettre
                        </button>
                      )}
                      {['soumis', 'en_analyse'].includes(d.status) && (
                        <button
                          className="crt-btn crt-btn-primary"
                          style={{ padding: '5px 10px', fontSize: 12 }}
                          disabled={actionLoading === d.id + '-devis'}
                          onClick={() => handleDemanderDevis(d.id)}
                        >
                          <i className="ti ti-file-invoice" /> Devis
                        </button>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}

        {!loading && !error && dossiers.length === 0 && (
          <div className="crt-empty">
            <i className="ti ti-folder-off" />
            <p>Aucun dossier trouvé</p>
          </div>
        )}
      </div>

      {showCreate && (
        <CreateDossierModal
          onClose={() => setShowCreate(false)}
          onCreated={() => { setShowCreate(false); load(); }}
        />
      )}
    </div>
  );
}
